import{_ as e,o as a,c as n,a2 as d}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"GamingQueue 事件模式","description":"","frontmatter":{},"headers":[],"relativePath":"dev/events-overview.md","filePath":"dev/events-overview.md","lastUpdated":1781182843000}'),s={name:"dev/events-overview.md"};function r(c,t,o,l,i,p){return a(),n("div",null,[...t[0]||(t[0]=[d(`<h1 id="gamingqueue-事件模式" tabindex="-1">GamingQueue 事件模式 <a class="header-anchor" href="#gamingqueue-事件模式" aria-label="Permalink to &quot;GamingQueue 事件模式&quot;">​</a></h1><p>GamingQueue 通过 <strong>31 个事件</strong> 将整个游戏循环暴露给外部，让开发者可以在客户端（UI 渲染）、服务端（网络同步）或 AI 系统中介入每个决策点。</p><blockquote><p>参考项目：<code>FunGame.Testing/Desktop/GameMapTesting</code> — WPF 实现的完整回合制演示，展示了所有事件的 UI 绑定模式。</p></blockquote><hr><h2 id="事件驱动架构" tabindex="-1">事件驱动架构 <a class="header-anchor" href="#事件驱动架构" aria-label="Permalink to &quot;事件驱动架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GamingQueue.ProcessTurn()</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ TurnStartEvent         ← 回合开始（可取消）</span></span>
<span class="line"><span>    │       │</span></span>
<span class="line"><span>    │       ├── AI 模式：自动决策</span></span>
<span class="line"><span>    │       │</span></span>
<span class="line"><span>    │       └── 玩家模式：</span></span>
<span class="line"><span>    │               DecideActionEvent    ← 选择行动类型</span></span>
<span class="line"><span>    │               SelectSkillEvent      ← 选择技能</span></span>
<span class="line"><span>    │               SelectItemEvent       ← 选择物品</span></span>
<span class="line"><span>    │               SelectNormalAttackTargetsEvent   ← 选择普攻目标</span></span>
<span class="line"><span>    │               SelectSkillTargetsEvent          ← 选择技能目标</span></span>
<span class="line"><span>    │               SelectNonDirectionalSkillTargetsEvent ← 选择非指向性目标</span></span>
<span class="line"><span>    │               SelectTargetGridEvent ← 选择移动目标</span></span>
<span class="line"><span>    │               CharacterInquiryEvent ← 询问玩家反应</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ CharacterNormalAttackEvent    ← 普攻执行</span></span>
<span class="line"><span>    ├──→ CharacterPreCastSkillEvent    ← 技能预释放</span></span>
<span class="line"><span>    ├──→ CharacterCastSkillEvent       ← 技能释放完成</span></span>
<span class="line"><span>    ├──→ CharacterUseItemEvent         ← 物品使用</span></span>
<span class="line"><span>    ├──→ CharacterMoveEvent            ← 角色移动</span></span>
<span class="line"><span>    ├──→ DamageToEnemyEvent            ← 造成伤害</span></span>
<span class="line"><span>    ├──→ HealToTargetEvent             ← 治疗</span></span>
<span class="line"><span>    ├──→ InterruptCastingEvent         ← 打断施法</span></span>
<span class="line"><span>    ├──→ DeathCalculationEvent         ← 死亡结算</span></span>
<span class="line"><span>    ├──→ CharacterDeathEvent           ← 角色死亡</span></span>
<span class="line"><span>    ├──→ CharacterImmunedEvent         ← 免疫触发</span></span>
<span class="line"><span>    ├──→ CharacterExemptionEvent       ← 豁免触发</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├──→ CharacterActionTakenEvent     ← 行动完成</span></span>
<span class="line"><span>    ├──→ CharacterDecisionCompletedEvent ← 决策完成</span></span>
<span class="line"><span>    ├──→ TurnEndEvent                  ← 回合结束</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └──→ QueueUpdatedEvent             ← 顺序表更新</span></span></code></pre></div><hr><h2 id="事件分类" tabindex="-1">事件分类 <a class="header-anchor" href="#事件分类" aria-label="Permalink to &quot;事件分类&quot;">​</a></h2><h3 id="一、游戏生命周期-2-个" tabindex="-1">一、游戏生命周期（2 个） <a class="header-anchor" href="#一、游戏生命周期-2-个" aria-label="Permalink to &quot;一、游戏生命周期（2 个）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>签名</th><th>返回值</th></tr></thead><tbody><tr><td><code>GameStartEvent</code></td><td><code>(GamingQueue queue)</code></td><td>void</td></tr><tr><td><code>GameEndEvent</code></td><td><code>(GamingQueue queue, Character winner)</code></td><td><code>bool</code></td></tr></tbody></table><h3 id="二、回合生命周期-3-个" tabindex="-1">二、回合生命周期（3 个） <a class="header-anchor" href="#二、回合生命周期-3-个" aria-label="Permalink to &quot;二、回合生命周期（3 个）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>签名</th><th>返回值</th></tr></thead><tbody><tr><td><code>TurnStartEvent</code></td><td><code>(GamingQueue queue, Character character, DecisionPoints dp, List&lt;Character&gt; enemys, List&lt;Character&gt; teammates, List&lt;Skill&gt; skills, List&lt;Item&gt; items)</code></td><td><code>bool</code></td></tr><tr><td><code>DecideActionEvent</code></td><td><code>(GamingQueue queue, Character character, DecisionPoints dp, ...)</code></td><td><code>CharacterActionType</code></td></tr><tr><td><code>TurnEndEvent</code></td><td><code>(GamingQueue queue, Character character, DecisionPoints dp)</code></td><td>void</td></tr></tbody></table><h3 id="三、交互式选择事件-7-个-—-需要用户-ui-输入" tabindex="-1">三、交互式选择事件（7 个）— 需要用户/UI 输入 <a class="header-anchor" href="#三、交互式选择事件-7-个-—-需要用户-ui-输入" aria-label="Permalink to &quot;三、交互式选择事件（7 个）— 需要用户/UI 输入&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>签名</th><th>返回值</th><th>用途</th></tr></thead><tbody><tr><td><code>SelectSkillEvent</code></td><td><code>(queue, character, List&lt;Skill&gt;)</code></td><td><code>Skill?</code></td><td>选技能</td></tr><tr><td><code>SelectItemEvent</code></td><td><code>(queue, character, List&lt;Item&gt;)</code></td><td><code>Item?</code></td><td>选物品</td></tr><tr><td><code>SelectNormalAttackTargetsEvent</code></td><td><code>(queue, character, NormalAttack, allEnemys, ...)</code></td><td><code>List&lt;Character&gt;</code></td><td>选普攻目标</td></tr><tr><td><code>SelectSkillTargetsEvent</code></td><td><code>(queue, caster, Skill, allEnemys, ...)</code></td><td><code>List&lt;Character&gt;</code></td><td>选指向性技能目标</td></tr><tr><td><code>SelectNonDirectionalSkillTargetsEvent</code></td><td><code>(queue, caster, Skill, enemys, teammates, castRange)</code></td><td><code>List&lt;Grid&gt;</code></td><td>选非指向性格子</td></tr><tr><td><code>SelectTargetGridEvent</code></td><td><code>(queue, character, enemys, teammates, map, moveRange)</code></td><td><code>Grid</code></td><td>选移动目标格子</td></tr><tr><td><code>CharacterInquiryEvent</code></td><td><code>(queue, character, dp, InquiryOptions)</code></td><td><code>InquiryResponse</code></td><td>询问玩家</td></tr></tbody></table><h3 id="四、动作执行事件-8-个-—-通知型" tabindex="-1">四、动作执行事件（8 个）— 通知型 <a class="header-anchor" href="#四、动作执行事件-8-个-—-通知型" aria-label="Permalink to &quot;四、动作执行事件（8 个）— 通知型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>触发时机</th></tr></thead><tbody><tr><td><code>CharacterNormalAttackEvent</code></td><td>普攻执行</td></tr><tr><td><code>CharacterPreCastSkillEvent</code></td><td>技能吟唱（含即时战技）</td></tr><tr><td><code>CharacterCastSkillEvent</code></td><td>技能释放完成（含消耗）</td></tr><tr><td><code>CharacterUseItemEvent</code></td><td>物品使用</td></tr><tr><td><code>CharacterCastItemSkillEvent</code></td><td>物品技能释放</td></tr><tr><td><code>CharacterMoveEvent</code></td><td>角色移动</td></tr><tr><td><code>CharacterDoNothingEvent</code></td><td>主动结束回合</td></tr><tr><td><code>CharacterGiveUpEvent</code></td><td>放弃行动</td></tr></tbody></table><h3 id="五、战斗事件-7-个-—-通知型" tabindex="-1">五、战斗事件（7 个）— 通知型 <a class="header-anchor" href="#五、战斗事件-7-个-—-通知型" aria-label="Permalink to &quot;五、战斗事件（7 个）— 通知型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>触发时机</th></tr></thead><tbody><tr><td><code>DamageToEnemyEvent</code></td><td>造成伤害</td></tr><tr><td><code>HealToTargetEvent</code></td><td>治疗</td></tr><tr><td><code>DeathCalculationEvent</code></td><td>死亡结算</td></tr><tr><td><code>DeathCalculationByTeammateEvent</code></td><td>击杀队友</td></tr><tr><td><code>CharacterDeathEvent</code></td><td>角色死亡（结算后）</td></tr><tr><td><code>InterruptCastingEvent</code></td><td>打断施法</td></tr><tr><td><code>CharacterImmunedEvent</code></td><td>免疫</td></tr><tr><td><code>CharacterExemptionEvent</code></td><td>豁免</td></tr></tbody></table><h3 id="六、状态变更事件-3-个" tabindex="-1">六、状态变更事件（3 个） <a class="header-anchor" href="#六、状态变更事件-3-个" aria-label="Permalink to &quot;六、状态变更事件（3 个）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>事件</th><th>触发时机</th></tr></thead><tbody><tr><td><code>QueueUpdatedEvent</code></td><td>顺序表变化</td></tr><tr><td><code>CharacterActionTakenEvent</code></td><td>行动完成</td></tr><tr><td><code>CharacterDecisionCompletedEvent</code></td><td>决策完成</td></tr></tbody></table>`,20)])])}const v=e(s,[["render",r]]);export{u as __pageData,v as default};
